const tickers = [
  "NVDA", "SPY", "BINANCE:BTCUSDT",   // holdings
  "PLTR", "HOOD", "TSLA", "ASTS",     // retail momentum
  "MU", "VRT", "CRDO", "CCJ",         // AI infrastructure
  "AMZN", "TTD"                        // mega-cap + fallen story
];

return tickers.map(t => ({ json: { symbol: t } }));

return items.map((item, i) => ({
  json: {
    symbol: $('Code in JavaScript').all()[i].json.symbol,
    price: item.json.c,
    dayChangePct: item.json.dp,
    prevClose: item.json.pc,
  }
}));

const rows = items.map(i => i.json);

const HOLDINGS = ["NVDA", "SPY", "BINANCE:BTCUSDT"];

const displayName = (s) => s === "BINANCE:BTCUSDT" ? "BTC" : s;

const fmt = (n) => n === null || n === undefined
  ? "n/a"
  : `${n >= 0 ? "+" : ""}${n.toFixed(2)}%`;

const line = (r) =>
  `**${displayName(r.symbol)}**  $${r.price.toLocaleString()}  |  day: ${fmt(r.dayChangePct)}`;

// Split into holdings vs watchlist
const holdings = rows.filter(r => HOLDINGS.includes(r.symbol));
const watching = rows.filter(r => !HOLDINGS.includes(r.symbol));

// Sort watchlist by biggest absolute daily move (n/a sinks to bottom)
watching.sort((a, b) =>
  Math.abs(b.dayChangePct ?? -Infinity) - Math.abs(a.dayChangePct ?? -Infinity)
);

const today = new Date().toLocaleDateString("en-US", { month: "long", day: "numeric" });

const message =
  `📊 **Daily Portfolio Digest — ${today}**\n\n` +
  `💼 **Holdings**\n${holdings.map(line).join("\n")}\n\n` +
  `👀 **Watching**\n${watching.map(line).join("\n")}`;

return [{ json: { content: message } }];

const fs = require('fs');

const DIR = '/Users/samallen/watchlist';

// Helper: date string like 2026-07-07, offset by n days
const dateStr = (offset) => {
  const d = new Date();
  d.setDate(d.getDate() - offset);
  return d.toISOString().slice(0, 10);
};

// Load a snapshot file for a given day-offset, or null
const loadSnapshot = (offset) => {
  try {
    const raw = fs.readFileSync(`${DIR}/snapshot-${dateStr(offset)}.json`, 'utf8');
    const map = {};
    for (const row of JSON.parse(raw)) map[row.symbol] = row.price;
    return map;
  } catch (e) {
    return null;
  }
};

// Yesterday's prices: try 1 day back, then 2, then 3 (weekends/missed runs)
let yesterday = null;
for (let o = 1; o <= 3 && !yesterday; o++) yesterday = loadSnapshot(o);

// Last week's prices: try 7 days back, then widen 6–10
let lastWeek = loadSnapshot(7);
for (let o = 6; o <= 10 && !lastWeek; o++) lastWeek = loadSnapshot(o);

const pct = (now, prev) =>
  prev ? Number((((now - prev) / prev) * 100).toFixed(2)) : null;

// Build output
const out = items.map(item => ({
  json: {
    symbol: item.json.symbol,
    price: item.json.price,
    dayChangePct: yesterday
      ? pct(item.json.price, yesterday[item.json.symbol])
      : item.json.dayChangePct,   // fall back to Finnhub's day change
    weeklyChangePct: lastWeek
      ? pct(item.json.price, lastWeek[item.json.symbol])
      : null,
  }
}));

// Save today's snapshot for future runs
const todayRows = items.map(i => ({ symbol: i.json.symbol, price: i.json.price }));
fs.writeFileSync(`${DIR}/snapshot-${dateStr(0)}.json`, JSON.stringify(todayRows));

return out;
